INSERT OR REPLACE INTO courses (id, operator_id, slug, title, summary, cover_color, emoji, primary_lang, status, est_minutes, ai_examples_json) VALUES
  ('c_coronet_peak_2026', 'op_nzski', 'coronet-peak-2026', 'Coronet Peak 2026', 'Queenstown''s pioneer ski field — terrain, lessons, snowmaking and the 2026 capital programme. Pitch with confidence to all guest types.', 'linear-gradient(135deg,#0e3d4a 0%, #134e5e 50%, #1a6679 100%)', '⛷️', 'en', 'published', 25, '["Heli Privates 适合什么水平?", "Snow-day cancellation policy", "Lift pass + rental combo pricing", "Bus shuttle from Queenstown CBD"]'),
  ('c_remarkables_2026', 'op_nzski', 'remarkables-2026', 'The Remarkables 2026', 'Queenstown''s family-favourite alpine resort, ringed by the iconic Remarkables range. 30% beginner, 40% intermediate terrain — pitch with confidence to families and intermediate-led groups.', 'linear-gradient(135deg,#1e293b 0%, #334155 100%)', '🏔️', 'en', 'published', 22, '["30/40/30 terrain split — where to send beginners?", "What''s new at The Remarkables for 2026?", "Ski bus schedule from Frankton", "Non-skier guest options"]'),
  ('c_mt_hutt_2026', 'op_nzski', 'mt-hutt-2026', 'Mt Hutt 2026', 'South Island''s highest commercial ski area and NZ''s longest season. Methven-based, accessible from Christchurch — great for shoulder-season pitches and guests prioritising snow reliability.', 'linear-gradient(135deg,#3d2f1f 0%, #6b4423 60%, #8b5a2b 100%)', '🏂', 'en', 'published', 24, '["Mt Hutt 比 Coronet Peak 6 月雪况更好吗?", "Chillfest 是什么时候?", "Methven 住宿推荐", "为什么 Mt Hutt 没有 Heli Privates?"]'),
  ('c_nzski_private_coaching', 'op_nzski', 'full-day-private-coaching', 'Full Day Private Coaching', 'Cross-resort private coaching offering — auto-drafted from 5 PDFs, pending operator review.', 'linear-gradient(135deg,#1f3a2e 0%, #2d5a3d 50%, #4a7c59 100%)', '🚁', 'en', 'draft', 0, NULL);

