INSERT OR REPLACE INTO content_blocks (id, module_id, position, kind, text_md, image_r2_key, video_uid, pdf_r2_key, caption, lang) VALUES
  ('b_m_cp_overview_000', 'm_cp_overview', 0, 'text', '**Coronet Peak** is NZSki''s pioneer ski field and the closest commercial ski area to Queenstown — just **25 minutes** from the CBD, which makes it the easy recommendation for guests who want a full day on snow and still enjoy town in the evening. The terrain suits **all abilities**: beginners progress on the Meadows and Kidzone learner carpets, while the open bowls and groomed runs give intermediates and families room to build confidence. The 2026 winter season runs **daily from June 13 to early October**, including Coronet''s well-known **night skiing** sessions on selected evenings.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_cp_overview_001', 'm_cp_overview', 1, 'callout', '**New for 2026 — Snow Factory.** Coronet Peak is now home to the **South Island''s first Snow Factory**, an all-weather system that produces premium snow **regardless of air temperature**. For your clients this means a far more reliable **early-season** product — groomed, skiable terrain from opening week even when natural snowfall is light, a strong reason to book Coronet for June and early-July departures.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_cp_overview_002', 'm_cp_overview', 2, 'text', 'The **2026 capital programme** improves the experience at both ends of the ability range. For families and first-timers, the **Kidzone learner area** gets an upgraded magic carpet for smoother, faster progression. For advanced guests, a **new Snowsports Heli Premium Private** experience launches alongside the existing private-coaching tiers, pairing backcountry heli access with one-on-one coaching. Together with the new Snow Factory, these upgrades make Coronet an easier sell across every guest profile you work with.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_cp_lifts_terrain_000', 'm_cp_lifts_terrain', 0, 'text', 'Lift network across Coronet''s bowl plus the M1 Express on the back face. Beginner zone fed by Meadows and Kidzone carpets; intermediates spread across Greengates / Rocky Gully; experts head to Back Bowls when conditions allow.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_cp_lifts_terrain_001', 'm_cp_lifts_terrain', 1, 'image', NULL, NULL, NULL, NULL, 'Coronet Peak base lodge — winter 2026', 'en'),
  ('b_m_cp_lessons_000', 'm_cp_lessons', 0, 'text', 'Coronet Peak offers **three tiers of private coaching**, each capped at 4 guests per instructor. Choosing the right tier depends on ability level and what the guest wants to get out of the day.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_cp_lessons_001', 'm_cp_lessons', 1, 'callout', '**Premium Privates** — family-friendly, all abilities. **NZ$ from 1,099/day**. Recommend for first-timers through to confident intermediates and mixed-ability groups.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_cp_lessons_002', 'm_cp_lessons', 2, 'callout', '**Performance Privates** — technique-focused for advanced skiers/snowboarders. **NZ$ from 1,299/day**. Recommend when the guest''s goal is measurable improvement.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_cp_lessons_003', 'm_cp_lessons', 3, 'callout', '**Premium Heli Privates** — backcountry heli access for advanced+ guests. **NZ$ from 2,890/day** including 2 drop-offs and full mountain-safety briefing. Subject to weather. Only available at Coronet Peak (not Remarkables or Mt Hutt).', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_cp_lessons_004', 'm_cp_lessons', 4, 'video', NULL, NULL, 'yt:aqz-KE-bpKQ', NULL, 'Coronet Peak — Aerial 2026 (DEMO video — swap to real NZSki YouTube ID before activity)', 'en'),
  ('b_m_cp_pricing_000', 'm_cp_pricing', 0, 'text', 'Day lift passes start at **NZ$ 169 adult / 99 child** at gate; **advance purchase** discounts available 14+ days out. 3-mountain pass (Coronet + Remarkables + Mt Hutt) is the best value for guests staying 4+ days in NZ.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_cp_booking_000', 'm_cp_booking', 0, 'text', 'Trade bookings via the NZSki Travel Trade portal. **Snow-day cancellation policy:** if the resort closes for the full day, lift-pass holders receive a credit (not refund) usable within 24 months at any NZSki resort. Lessons and heli are rebooked subject to availability or fully refunded.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_tr_overview_000', 'm_tr_overview', 0, 'text', '**The Remarkables** sits 24 km (45 min) from central Queenstown via 9 km sealed + 4 km unsealed access road. Targeted opening **13 June 2026**. Peak elevation **1,943 m**, vertical drop **468 m**, average snowfall **3.67 m per annum** (excl. snowmaking).', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_tr_overview_001', 'm_tr_overview', 1, 'callout', '**New for 2026** — expanded café with 200+ additional seats, café-deck fire pits with BBQ + music, increased Ski Bus capacity (3 new MAN 4WD coaches + a 4th mid-season), and additional snow machines.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_tr_overview_002', 'm_tr_overview', 2, 'text', 'The Remarkables ski area is part of family-owned NZSki, alongside Coronet Peak (Queenstown) and Mt Hutt (Methven). Strong family draw plus enough advanced terrain (Alta Chutes / Homeward Bound) to satisfy expert guests on the same day.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_tr_terrain_000', 'm_tr_terrain', 0, 'text', 'Terrain split: **30% beginner, 40% intermediate, 30% advanced**. Lifts: **three high-speed six-seater chairs**, one quad chair, and **four surface conveyors** (three with covered galleries).', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_tr_terrain_001', 'm_tr_terrain', 1, 'callout', '**Iconic named runs**: City, Curvey, Cross Fall, Serpentine, Turquoise, Waterfall, Calypso, Mid Steeps — plus dedicated terrain parks.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_tr_terrain_002', 'm_tr_terrain', 2, 'text', '**Where to send guests**: First-timers → Meadows / surface conveyors. Confident intermediates → Sugar Bowl + Shadow Basin. Advanced → Alta Chutes, Homeward Bound, and back-bowl access via Curvey traverses.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_tr_lessons_family_000', 'm_tr_lessons_family', 0, 'text', 'Private and group coaching, kids programmes from age 3, high-performance camps, and adaptive snowsports. Capped class sizes mean confident progression for first-timers in a single day.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_tr_lessons_family_001', 'm_tr_lessons_family', 1, 'callout', '**Non-skier guests**: scenic chair rides on First Chair, lunch at the Aperol Ice Bar or main restaurant, sledding zone, and beginner snow-experience packages.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_tr_food_facilities_000', 'm_tr_food_facilities', 0, 'text', 'F&B lineup: full-service restaurant + bar, café, **Aperol Ice Bar**, and Barista Bar. The 2026 café expansion adds 200+ seats and a deck with fire pits, BBQ and a custom park sound system.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_tr_food_facilities_001', 'm_tr_food_facilities', 1, 'text', '**Sustainability**: in 2024 NZSki introduced Sorting Stations across all outlets — reduced waste to landfill by 42% through composting. Carbon credits purchased via Climate Action. Ongoing planting, revegetation and pest control on the mountain.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_tr_booking_transport_000', 'm_tr_booking_transport', 0, 'text', '**Ski Bus**: dedicated scheduled service from central Queenstown before 9 am and Frankton after 9.30 am. 2026 fleet expansion adds 3 new MAN 4WD coaches (+ 1 mid-season) — capacity issues common in 2024/25 are addressed.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_tr_booking_transport_001', 'm_tr_booking_transport', 1, 'text', '**Snow-day policy** (NZSki-wide): if the resort closes for the full day, lift-pass holders receive a **credit** (not refund) usable within 24 months at any NZSki resort. Lessons/heli rebooked subject to availability or fully refunded.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_tr_booking_transport_002', 'm_tr_booking_transport', 2, 'callout', '**3-Mountain pass** (Coronet + Remarkables + Mt Hutt) is best value for guests staying **4+ days** in NZ. Strongly recommend for South Island multi-stop itineraries.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_mh_overview_000', 'm_mh_overview', 0, 'text', '**Mt Hutt** is NZ''s longest ski season — targeted opening **12 June 2026**, often running into mid-October. Peak elevation **2,086 m** (the highest commercial ski area in the South Island), vertical drop **683 m**. 1 hr 30 min drive from Christchurch International Airport via Methven.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_mh_overview_001', 'm_mh_overview', 1, 'callout', '**Positioning tip**: Mt Hutt is the answer when a guest wants to ski in **June** (Queenstown fields often patchy in early June) or in **October** when other fields have closed.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_mh_overview_002', 'm_mh_overview', 2, 'text', 'Sister to Coronet Peak and The Remarkables — same NZSki ownership, same lift-pass and booking systems. 3-Mountain pass holders enjoy all three on one ticket.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_mh_terrain_000', 'm_mh_terrain', 0, 'text', 'Mt Hutt offers wide-open faces, well-suited to intermediates building confidence. The high altitude means lighter, drier snow than Queenstown fields on most days.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_mh_terrain_001', 'm_mh_terrain', 1, 'callout', '**Lift network**: high-speed six-pack chair (Heritage Chair) + Summit Six + Triple chair + magic-carpet learner zone. The Six-Star Express opens up the South Face and back bowls in good weather.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_mh_lessons_000', 'm_mh_lessons', 0, 'text', 'Mt Hutt offers **two tiers of private coaching**: Premium Privates (family-friendly, all abilities, **NZ$ from 1,099/day**) and Performance Privates (advanced, technique-focused, **NZ$ from 1,299/day**). Each session is capped at 4 guests per instructor.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_mh_lessons_001', 'm_mh_lessons', 1, 'callout', '**Important**: Premium Heli Privates are **Coronet Peak only**. Don''t promise heli access to guests buying a Mt Hutt-only itinerary — direct them to Coronet for the day if it''s the differentiator.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_mh_lessons_002', 'm_mh_lessons', 2, 'text', 'Kids programmes from age 3, high-performance camps, and adaptive snowsports — same structure as the other two NZSki resorts.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_mh_events_2026_000', 'm_mh_events_2026', 0, 'text', '**Chillfest** (19 Sep) — Mt Hutt''s biggest party of the season, on-mountain music + après. **Moon Ski** (26 Sep) — limited-capacity night-skiing event under a full moon. Use these as ''reason to stay extra nights in Methven'' when pitching trips.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_mh_events_2026_001', 'm_mh_events_2026', 1, 'text', 'Mid-week junior race series runs **27–28 Jun, 27–28 Jul, 28 Aug** — useful for parents wanting structured kid programming.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_mh_access_booking_000', 'm_mh_access_booking', 0, 'text', '**Base town**: Methven (population ~1,800) — the entire town is geared around the ski season. Most guests stay 2–4 nights. Christchurch (1 hr 30 min drive) is the alternative for guests who want city amenities + day-trip skiing.', NULL, NULL, NULL, NULL, 'en'),
  ('b_m_mh_access_booking_001', 'm_mh_access_booking', 1, 'callout', '**Trade booking**: NZSki Travel Trade portal handles all three resorts in one PNR. Snow-day credit policy is identical to the other resorts (credit, not refund, valid 24 months at any NZSki resort).', NULL, NULL, NULL, NULL, 'en');

